"use strict";new Swiper(".swiper-container",SWIPER_CONFIG);layui.use(["flow","util"],function(){let flow=layui.flow;let util=layui.util;flow.load({elem:".articles",isAuto:true,end:"没有更多了",done:function(b,a){let lis=[];$.ajax({url:"/re/blog/listBlogPage",method:"GET",data:{page:b,count:10},dataType:"json",success:function(c){if(c.request==="success"&&c.status===200){layui.each(c.data,function(d,e){if(e.status===1){let text='<article class="article mb10 p10">    <header class="article-header mb10">        <a href="/re/articles/'+e.type+'">             <span class="article-label f12 mr5">'+e.type+'<i class="label-arrow"></i></span>        </a>         <a href="/re/article/'+e.id+'">            <span class="article-title f14">'+e.title+'</span>        </a>    </header>    <section class="article-detail flex">        <div class="mr10 article-thumb cursor-pointer">            <img src="'+e.coverImage+'" alt="'+e.title+'" title="'+e.title+'">        </div>        <div class="article-summary flex flex-direction-column flex-justify-content-space-between">            <a href="/re/article/'+e.id+'">'+e.summary+'            </a>            <div class="article-info">                <a href="#">                    <i class="fa fa-user pr5" aria-hidden="true"></i>                    <span style="color: #00A67C;">'+e.author+'</span></a>                <a href="#">                    <i class="fa fa-clock-o" aria-hidden="true"></i>                    <span>'+util.toDateString(e.modifyTime,"yyyy-MM-dd")+'</span>                </a>                 <a href="#">                    <i class="fa fa-eye" aria-hidden="true"></i>                    <span>'+e.view+'浏览</span>                </a>                 <a href="#">                    <i class="fa fa-comment" aria-hidden="true"></i>                    <span>'+e.comment+"评论</span>                </a>            </div>        </div>    </section></article>";lis.push(text)}});a(lis.join(""),b<c.fields.totalPages)}}})}})});